// Stop() method (lines 63-73):
func (c *Cache) Stop() {
    c.mu.Lock()
    defer c.mu.Unlock()

    if c.cancel != nil {
        c.cancel()
    }

    // Also signal via stopChan for backward compatibility
    if c.stopChan != nil {
        close(c.stopChan)
    }
}

